import{_ as t,o as r,c as a,a2 as o}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"Projects","description":"","frontmatter":{},"headers":[],"relativePath":"app/projects.md","filePath":"app/projects.md"}'),n={name:"app/projects.md"};function s(i,e,l,c,p,d){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="projects" tabindex="-1">Projects <a class="header-anchor" href="#projects" aria-label="Permalink to &quot;Projects&quot;">​</a></h1><p>A project is a single application managed by Tragwerk. It belongs to a <a href="/app/teams">team</a>, targets a <a href="/self-hosting/servers">server</a> and a container <a href="/app/registries-credentials">registry</a>, and points at a git repository. Each git branch of that repository can be deployed as an isolated <a href="/app/environments">environment</a>.</p><h2 id="create-a-project" tabindex="-1">Create a project <a class="header-anchor" href="#create-a-project" aria-label="Permalink to &quot;Create a project&quot;">​</a></h2><ol><li>Open <strong>Projects</strong> in the active team and click <strong>Create project</strong>.</li><li>Enter a <strong>Project name</strong>.</li><li>Pick the <strong>Server</strong> this project deploys to.</li><li>Pick the <strong>Container registry</strong> used to store built images.</li><li>Click <strong>Create project</strong>.</li></ol><div class="tip custom-block"><p class="custom-block-title">Servers and registries first</p><p>The Server and Registry dropdowns only list resources that already exist in the team. Add a <a href="/self-hosting/servers">server</a> and a <a href="/app/registries-credentials">registry</a> before creating the project if the lists are empty.</p></div><h2 id="the-project-overview" tabindex="-1">The project overview <a class="header-anchor" href="#the-project-overview" aria-label="Permalink to &quot;The project overview&quot;">​</a></h2><p>Opening a project shows a stat strip and live tables:</p><ul><li><strong>Production URL</strong> — the primary domain of the production (root) environment, if one is deployed.</li><li><strong>Environments</strong> — how many branches are deployed as environments.</li><li><strong>Last commit</strong> — the most recent commit on the production environment.</li><li><strong>Last deploy</strong> — when production was last deployed.</li><li><strong>Environments table</strong> — every branch deployed as an environment, with live status (updated over Mercure SSE).</li><li><strong>Activity</strong> — a feed of recent deploy jobs.</li><li><strong>Configuration</strong> — the stack (PHP 8.5), the target server and registry, and the <strong>Git clone URL</strong> Tragwerk uses to fetch your code.</li></ul><p>Use <strong>Open production</strong> to visit the live site, and <strong>Settings</strong> to edit the project.</p><h2 id="edit-a-project" tabindex="-1">Edit a project <a class="header-anchor" href="#edit-a-project" aria-label="Permalink to &quot;Edit a project&quot;">​</a></h2><p>From <strong>Settings</strong> you can change the project <strong>name</strong>, its <strong>server</strong> and its <strong>registry</strong>. Save your changes with <strong>Save changes</strong>.</p><h2 id="delete-a-project" tabindex="-1">Delete a project <a class="header-anchor" href="#delete-a-project" aria-label="Permalink to &quot;Delete a project&quot;">​</a></h2><p>The Settings page has a <strong>Danger zone</strong>. Click <strong>Delete project</strong> and confirm in the dialog.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Deleting a project permanently removes it and all associated resources (environments, containers and data). This cannot be undone.</p></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/app/environments">Environments</a></li><li><a href="/app/deployments">Deployments</a></li><li><a href="/app/domains">Domains &amp; SSL</a></li><li><a href="/app/variables">Environment Variables</a></li><li><a href="/config/overview">Configuration overview</a></li></ul>',16)])])}const m=t(n,[["render",s]]);export{g as __pageData,m as default};
